            try {
                const runner = new TestRunner();
                await runner.initialize();
                const result = await runner.engine.processUserInput(input);

                log('\n--- COUNCIL RESPONSES ---');
                for (const response of result.responses) {
                    log(`\n[${response.name}]: ${response.response}`);
                }

                log('\n--- RESOLUTION ---');
                if (result.resolution?.type === 'consensus') {
                    log(`Consensus reached: ${result.resolution.position}`);
                } else if (result.resolution?.type === 'split') {
                    log(`Split: ${result.resolution.positions.join(' vs ')}`);
                } else {
                    log('No resolution reached.');
                }
            } catch (error) {
                log(`❌ ERROR: ${error.message}`, true);
            }
        }

        // Bind buttons
