                    document.getElementById('chatLog').appendChild(godDiv);
                }

                if (result.resolution?.type === 'consensus') {
                    addChatMessage('system', `✨ Council reached consensus: ${result.resolution.position}`);
                } else if (result.resolution?.type === 'split') {
                    addChatMessage('system', `⚡ Council split: ${result.resolution.positions.join(' vs ')}`);
                }

                updateMemoryView();
            } catch (error) {
                addChatMessage('system', `❌ Error: ${error.message}`);
                console.error(error);
            }
        }

        async function showGodDebug(godId, context) {
            if (!engine) return;
            const debug = engine.getGodDebugState(godId, { topic: 'general', userInput: context });
            const div = document.getElementById('godDebug');
            div.innerHTML = `
                <div style="color: #ffaa66;">${debug.name} (${debug.god})</div>
                <hr>
                <div><strong>Retrieved Memories:</strong></div>
                ${debug.retrieved_memories.map(m => `
                    <div style="margin-left: 10px; font-size: 10px;">📖 ${m.summary.substring(0, 50)}... (relevance: ${m.relevance.toFixed(2)})</div>
                `).join('') || '<div>None</div>'}
                <div><strong>Internal Impulses:</strong></div>
                <div style="margin-left: 10px;">Profit: ${debug.internal_impulses.profit.toFixed(2)} | Love: ${debug.internal_impulses.love.toFixed(2)} | Tax: ${debug.internal_impulses.tax.toFixed(2)}</div>
