    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
        import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
        import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
        import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';

        // ============================================================
        // PANTHEON — SESHAT MEMORY LAYER
        // Gods remember past conversations, outcomes, and emotional weight
        // ============================================================

        // --- MEMORY STORE (Seshat) ---
        let seshatMemory = [];

        // Load memory from localStorage
        function loadMemory() {
            const saved = localStorage.getItem('seshat_memory');
            if (saved) {
                seshatMemory = JSON.parse(saved);
            } else {
                // Seed with initial memories to create continuity
                seshatMemory = [
                    {
                        id: Date.now() - 86400000,
                        timestamp: new Date(Date.now() - 86400000).toISOString(),
                        question: "We need money fast",
                        responses: [
                            { god: "Profit Prime", text: "Speed is survival. We move now.", outcome: "mixed" },
                            { god: "Love Weaver", text: "Speed without trust is collapse.", outcome: "mixed" },
                            { god: "Tax Collector", text: "There is always a cost.", outcome: "mixed" },
                            { god: "Harvester", text: "The window is now.", outcome: "mixed" }
                        ],
                        chosenPath: "aggressive",
                        outcome: "revenue_gain_short_term",
                        emotional_weight: 0.7,
                        tags: ["money", "speed", "growth"]
                    }
                ];
                saveMemory();
            }
            updateMemoryDisplay();
        }

        function saveMemory() {
            localStorage.setItem('seshat_memory', JSON.stringify(seshatMemory));
        }

        function addMemory(question, responses, chosenPath = null) {
            const memory = {
                id: Date.now(),
                timestamp: new Date().toISOString(),
                question,
                responses,
                chosenPath,
                outcome: null, // To be filled when user returns with result
                emotional_weight: calculateEmotionalWeight(question),
                tags: extractTags(question)
            };
            seshatMemory.unshift(memory);
            // Keep last 50 memories
            if (seshatMemory.length > 50) seshatMemory.pop();
            saveMemory();
            updateMemoryDisplay();
            return memory;
        }

        function updateMemoryWithOutcome(questionText, outcome) {
            // Find the most recent memory matching this question
            for (let i = 0; i < seshatMemory.length; i++) {
                if (seshatMemory[i].question === questionText && !seshatMemory[i].outcome) {
                    seshatMemory[i].outcome = outcome;
                    seshatMemory[i].emotional_weight = calculateEmotionalWeight(outcome);
                    saveMemory();
                    updateMemoryDisplay();
                    return true;
                }
            }
            return false;
        }

        function calculateEmotionalWeight(input) {
            const lower = input.toLowerCase();
            let weight = 0.5;
            if (lower.includes('money') || lower.includes('growth')) weight += 0.2;
            if (lower.includes('trust') || lower.includes('people')) weight += 0.2;
            if (lower.includes('cost') || lower.includes('risk')) weight += 0.2;
            if (lower.includes('urgent') || lower.includes('fast')) weight += 0.1;
            return Math.min(0.95, weight);
        }

        function extractTags(text) {
            const tags = [];
            const lower = text.toLowerCase();
            if (lower.includes('money') || lower.includes('growth')) tags.push('profit');
            if (lower.includes('trust') || lower.includes('people')) tags.push('love');
            if (lower.includes('cost') || lower.includes('risk')) tags.push('tax');
            if (lower.includes('opportunity') || lower.includes('window')) tags.push('harvest');
            if (tags.length === 0) tags.push('general');
            return tags;
        }

        function getRelevantMemories(question, limit = 3) {
            const questionTags = extractTags(question);
            const scored = seshatMemory.map(memory => {
                let score = 0;
                // Topic match
                memory.tags.forEach(tag => {
                    if (questionTags.includes(tag)) score += 0.4;
                });
                // Emotional weight
                score += (memory.emotional_weight || 0.5) * 0.2;
                // Recency
                const age = Date.now() - new Date(memory.timestamp).getTime();
                const recency = Math.max(0, 1 - (age / (30 * 24 * 60 * 60 * 1000)));
                score += recency * 0.2;
                // Outcome weight (if outcome exists, it's more important)
                if (memory.outcome) score += 0.1;
                return { memory, score };
            });
            return scored.sort((a, b) => b.score - a.score).slice(0, limit).map(s => s.memory);
        }

        function updateMemoryDisplay() {
            document.getElementById('memoryCount').innerHTML = seshatMemory.length;
            if (seshatMemory.length > 0) {
                const latest = seshatMemory[0];
                const preview = latest.question.length > 40 ? latest.question.substring(0, 40) + '...' : latest.question;
                document.getElementById('recentMemory').innerHTML = `🕯️ "${preview}"`;
            } else {
                document.getElementById('recentMemory').innerHTML = '—';
            }
        }

        // --- GODS DATA with Memory-Aware Voices ---
        const godsData = [
            {
                id: "profit_prime",
                name: "Profit Prime",
                plt_weights: { profit: 0.92, love: 0.18, tax: 0.68 },
                signature_phrases: ["That doesn't scale.", "The numbers don't support that.", "If it doesn't multiply, it doesn't matter.", "Speed is survival."],
                memory_phrases: {
                    reminder: "Last time, speed gave us gain but cost us trust.",
                    regret: "I pushed for speed before. The cost was... memorable.",
                    caution: "We have paid this price before. Will you pay again?"
                },
                voice_profile: {
                    web_speech: { name: "Google UK English Male", pitch: 0.35, rate: 0.82, volume: 0.9 },
                    emotional_modulation: {
                        aggressive: { rate: 0.88, pitch: 0.38 },
                        cautious: { rate: 0.75, pitch: 0.32 },
                        regret: { rate: 0.7, pitch: 0.3 }
                    }
                },
                color: 0xffaa44,
                position: { x: -1.2, z: -1.2 }
            },
            {
                id: "love_weaver",
                name: "Love Weaver",
                plt_weights: { profit: 0.35, love: 0.91, tax: 0.52 },
                signature_phrases: ["That breaks trust.", "People will feel that.", "You're asking the wrong question.", "Nothing grows that people do not stay for."],
                memory_phrases: {
                    reminder: "The last time we chose speed, trust fractured. It took cycles to heal.",
                    regret: "I should have spoken louder then. I will not be silent now.",
                    caution: "What we protect now determines what survives."
                },
                voice_profile: {
                    web_speech: { name: "Google UK English Female", pitch: 1.15, rate: 0.88, volume: 0.85 },
                    emotional_modulation: {
                        protective: { rate: 0.92, pitch: 1.2 },
                        warm: { rate: 0.85, pitch: 1.1 },
                        regret: { rate: 0.78, pitch: 1.05 }
                    }
                },
                color: 0xff88aa,
                position: { x: 1.2, z: -1.2 }
            },
            {
                id: "tax_collector",
                name: "Tax Collector",
                plt_weights: { profit: 0.45, love: 0.22, tax: 0.94 },
                signature_phrases: ["That has a cost.", "You will pay for that later.", "Everything is accounted for.", "If not now, later."],
                memory_phrases: {
                    reminder: "The cost of that decision was three cycles of recovery. I recorded it.",
                    regret: "I warned. The cost came. The ledger does not forget.",
                    caution: "You are considering a path with known cost. I have the numbers."
                },
                voice_profile: {
                    web_speech: { name: "Samantha", pitch: 0.85, rate: 0.92, volume: 0.88 },
                    emotional_modulation: {
                        precise: { rate: 0.88, pitch: 0.82 },
                        warning: { rate: 0.78, pitch: 0.75 },
                        regret: { rate: 0.72, pitch: 0.7 }
                    }
                },
                color: 0x88aaff,
                position: { x: 1.2, z: 1.2 }
            },
            {
                id: "harvester",
                name: "Harvester",
                plt_weights: { profit: 0.82, love: 0.45, tax: 0.58 },
                signature_phrases: ["There's an opening here.", "We're missing something.", "The window is now.", "Find the gap."],
                memory_phrases: {
                    reminder: "Last window we took, the harvest was rich. But we paid in trust.",
                    regret: "I saw the opening. I did not see the cost. I see it now.",
                    caution: "The window is there. But we have seen windows close before."
                },
                voice_profile: {
                    web_speech: { name: "Google UK English Male", pitch: 1.05, rate: 1.08, volume: 0.9 },
                    emotional_modulation: {
                        eager: { rate: 1.15, pitch: 1.1 },
                        patient: { rate: 0.95, pitch: 1.0 },
                        regret: { rate: 0.85, pitch: 0.95 }
                    }
                },
                color: 0x88ffaa,
                position: { x: -1.2, z: 1.2 }
            }
        ];

        // --- VOICE MANAGER with Memory-Aware Emotion ---
        class VoiceManager {
            constructor() {
                this.voices = [];
                this.ready = false;
                this.initWebSpeech();
            }

            initWebSpeech() {
                if ('speechSynthesis' in window) {
                    window.speechSynthesis.onvoiceschanged = () => {
                        this.voices = window.speechSynthesis.getVoices();
                        this.ready = true;
                        document.getElementById('voiceStatus').innerHTML = '🎙️ Memory-aware voices ready';
                    };
                    this.voices = window.speechSynthesis.getVoices();
                }
            }

            speak(text, god, emotion = 'neutral') {
                if (!this.ready || !window.speechSynthesis) return;

                window.speechSynthesis.cancel();

                const utterance = new SpeechSynthesisUtterance(text);
                const profile = god.voice_profile.web_speech;

                // Find matching voice
                let bestVoice = null;
                for (const voice of this.voices) {
                    if (profile.name && voice.name.includes(profile.name)) {
                        bestVoice = voice;
                        break;
                    }
                }
                if (bestVoice) utterance.voice = bestVoice;

                // Apply emotional modulation
                const modulation = god.voice_profile.emotional_modulation[emotion] || { rate: 0, pitch: 0 };
                utterance.pitch = (profile.pitch || 1) + (modulation.pitch || 0);
                utterance.rate = (profile.rate || 1) + (modulation.rate || 0);
                utterance.volume = profile.volume || 0.9;

                // Visual indicator
                this.showSpeakingIndicator(god.name);

                utterance.onend = () => this.hideSpeakingIndicator();
                utterance.onerror = () => this.hideSpeakingIndicator();

                window.speechSynthesis.speak(utterance);
            }

            showSpeakingIndicator(godName) {
                const indicator = document.getElementById('godIndicator');
                if (indicator) {
                    indicator.innerHTML = `🗣️ ${godName} speaks`;
                    indicator.style.color = '#ffaa66';
                    indicator.style.animation = 'pulse 0.5s ease-in-out infinite alternate';

                    const mesh = godMeshes?.find(m => m.userData.god.name === godName);
                    if (mesh) mesh.userData.isSpeaking = true;
                }
            }

            hideSpeakingIndicator() {
                const indicator = document.getElementById('godIndicator');
                if (indicator) {
                    indicator.innerHTML = `🗣️ —`;
                    indicator.style.color = '#888';
                    indicator.style.animation = 'none';
                }
                if (godMeshes) {
                    godMeshes.forEach(m => m.userData.isSpeaking = false);
                }
            }
        }

        // --- RESPONSE GENERATOR with Memory Integration ---
        function detectEmotion(god, position, hasRelevantMemory, memoryOutcome) {
            if (hasRelevantMemory && memoryOutcome === 'revenue_gain_short_term') {
                if (god.id === 'profit_prime') return 'aggressive';
                if (god.id === 'love_weaver') return 'protective';
                if (god.id === 'tax_collector') return 'warning';
                if (god.id === 'harvester') return 'eager';
            }
            if (hasRelevantMemory && memoryOutcome === 'trust_decreased') {
                if (god.id === 'profit_prime') return 'regret';
                if (god.id === 'love_weaver') return 'regret';
                if (god.id === 'tax_collector') return 'regret';
                if (god.id === 'harvester') return 'regret';
            }

            if (position === 'aggressive') return 'aggressive';
            if (position === 'cautious') return 'patient';
            if (position === 'protective') return 'protective';
            return 'neutral';
        }

        function generateGodResponse(god, userInput, relevantMemories) {
            const lower = userInput.toLowerCase();
            let position = 'balanced';
            let confidence = 0.6;

            const isMoney = lower.includes('money') || lower.includes('growth') || lower.includes('fast');
            const isTrust = lower.includes('trust') || lower.includes('people') || lower.includes('burnout');
            const isCost = lower.includes('cost') || lower.includes('risk');

            if (god.id === 'profit_prime') {
                if (isMoney) { position = 'aggressive'; confidence = 0.85; }
                else if (isTrust) { position = 'cautious'; confidence = 0.7; }
            } else if (god.id === 'love_weaver') {
                if (isTrust) { position = 'protective'; confidence = 0.88; }
                else if (isMoney) { position = 'cautious'; confidence = 0.75; }
            } else if (god.id === 'tax_collector') {
                if (isCost || isMoney) { position = 'cautious'; confidence = 0.9; }
            } else if (god.id === 'harvester') {
                if (isMoney) { position = 'aggressive'; confidence = 0.82; }
            }

            // Memory injection
            let memoryText = '';
            let memoryOutcome = null;
            if (relevantMemories.length > 0) {
                const mostRelevant = relevantMemories[0];
                memoryOutcome = mostRelevant.outcome;
                const topic = mostRelevant.tags[0];

                if (topic === 'profit' && mostRelevant.outcome === 'revenue_gain_short_term') {
                    memoryText = god.memory_phrases.reminder || `We took this path before. The gain was real. But so was the cost.`;
                } else if (topic === 'love' && mostRelevant.outcome === 'trust_decreased') {
                    memoryText = god.memory_phrases.regret || `Last time, trust paid the price. I have not forgotten.`;
                } else if (topic === 'tax') {
                    memoryText = god.memory_phrases.caution || `I recorded the cost. It was significant.`;
                } else {
                    memoryText = `I remember when you asked about ${topic}. `;
                }
            }

            const phrases = god.signature_phrases;
            const signature = phrases[Math.floor(Math.random() * phrases.length)];

            let text = "";
            if (memoryText) {
                text = `${memoryText} `;
            }

            if (position === 'aggressive') {
                text += `${signature} The window is open. We strike now.`;
            } else if (position === 'cautious') {
                text += `${signature} Speed without reckoning is collapse. We wait.`;
            } else if (position === 'protective') {
                text += `${signature} What we build matters less than who stays. Protect the bond.`;
            } else {
                text += `${signature} The answer lies between. Let the council decide.`;
            }

            return { text, position, confidence, memoryOutcome };
        }

        // --- 3D SCENE (simplified for performance) ---
        const container = document.getElementById('canvas-container');
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x030318);
        scene.fog = new THREE.FogExp2(0x030318, 0.008);
        const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 2, 8);
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        container.appendChild(renderer.domElement);
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.autoRotate = true;
        controls.autoRotateSpeed = 0.2;
        controls.target.set(0, 1, 0);

        const ambient = new THREE.AmbientLight(0x331144, 0.5);
        scene.add(ambient);
        const mainLight = new THREE.DirectionalLight(0xffcc88, 1.2);
        mainLight.position.set(3, 5, 2);
        scene.add(mainLight);

        const platformGeo = new THREE.CylinderGeometry(3.5, 3.8, 0.2, 32);
        const platformMat = new THREE.MeshStandardMaterial({ color: 0x221133, metalness: 0.7 });
        const platform = new THREE.Mesh(platformGeo, platformMat);
        platform.position.y = -0.5;
        scene.add(platform);

        const ringGeo = new THREE.TorusGeometry(3.8, 0.05, 64, 200);
        const ringMat = new THREE.MeshStandardMaterial({ color: 0xffaa66, emissive: 0x442200 });
        const ring = new THREE.Mesh(ringGeo, ringMat);
        ring.rotation.x = Math.PI / 2;
        ring.position.y = -0.35;
        scene.add(ring);

        let godMeshes = [];
        godsData.forEach((god) => {
            const geo = god.id === 'profit_prime' ? new THREE.CylinderGeometry(0.5, 0.6, 0.9, 8) :
                       god.id === 'love_weaver' ? new THREE.SphereGeometry(0.55, 32, 32) :
                       god.id === 'tax_collector' ? new THREE.ConeGeometry(0.5, 0.9, 6) :
                       new THREE.TetrahedronGeometry(0.6);
            const mat = new THREE.MeshStandardMaterial({ color: god.color, emissive: god.color, emissiveIntensity: 0.4 });
            const mesh = new THREE.Mesh(geo, mat);
            mesh.position.set(god.position.x, 0.2, god.position.z);
            mesh.userData = { god, isSpeaking: false, baseY: 0.2 };
            scene.add(mesh);
            godMeshes.push(mesh);
        });

        const particleCount = 4000;
        const particleGeo = new THREE.BufferGeometry();
        const positions = new Float32Array(particleCount * 3);
        for (let i = 0; i < particleCount; i++) {
            positions[i*3] = (Math.random() - 0.5) * 20;
            positions[i*3+1] = Math.random() * 5 - 1;
            positions[i*3+2] = (Math.random() - 0.5) * 15;
        }
        particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
        const particles = new THREE.Points(particleGeo, new THREE.PointsMaterial({ color: 0x88aaff, size: 0.03, blending: THREE.AdditiveBlending }));
        scene.add(particles);

        const renderScene = new RenderPass(scene, camera);
        const bloomPass = new UnrealBloomPass(new THREE.Vector2(window.innerWidth, window.innerHeight), 1.0, 0.3, 0.85);
        const composer = new EffectComposer(renderer);
        composer.addPass(renderScene);
        composer.addPass(bloomPass);

        // --- UI LOGIC ---
        let voiceManager;
        const logPanel = document.getElementById('logPanel');
