            logPanel.appendChild(entry);
            entry.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            while (logPanel.children.length > 45) logPanel.removeChild(logPanel.firstChild);
        }

        async function sendMessage(text) {
