// ============================================================
// PREDICTIVE INSIGHTS — Churn & Upgrade Intelligence
// Uses behavioral patterns to predict which users will:
// - Churn (stop using)
// - Upgrade (convert to premium)
// - Need intervention
// ============================================================

class PredictiveInsights {
    constructor() {
        this.models = {
            churn: this.initChurnModel(),
            upgrade: this.initUpgradeModel(),
            engagement: this.initEngagementModel()
        };
    }

    // Churn Prediction Model
    // Returns probability (0-1) that user will churn in next 30 days
    predictChurnRisk(user) {
        let risk = 0.2; // Base risk

        // Factor 1: Days since last active
        const daysSinceActive = user.lastActive ? 
            (Date.now() - user.lastActive) / (1000 * 60 * 60 * 24) : 30;
        if (daysSinceActive > 7) risk += 0.15;
        if (daysSinceActive > 14) risk += 0.2;
        if (daysSinceActive > 30) risk += 0.3;

        // Factor 2: Message count trend (declining engagement)
        if (user.messageCount && user.messageTrend === 'declining') risk += 0.2;

        // Factor 3: No premium conversion after high usage
        if (user.messageCount > 20 && user.segment === 'free') risk += 0.15;

        // Factor 4: Negative sentiment in recent messages
        if (user.recentSentiment === 'negative') risk += 0.2;

        // Factor 5: No response to god advice (ignored)
        if (user.followThrough === 'low') risk += 0.15;

        return Math.min(0.95, risk);
    }

    // Upgrade Prediction Model
    // Returns probability (0-1) that user will upgrade to premium
    predictUpgradeLikelihood(user) {
        let likelihood = 0.05; // Base likelihood

        // Factor 1: High message count
        if (user.messageCount > 10) likelihood += 0.15;
        if (user.messageCount > 30) likelihood += 0.2;

        // Factor 2: High emotional intensity (urgent questions)
        if (user.emotionalIntensity > 0.7) likelihood += 0.15;

        // Factor 3: Asked about money/growth
        if (user.topics?.profit > 5) likelihood += 0.2;

        // Factor 4: Received valuable advice
        if (user.satisfactionScore > 0.7) likelihood += 0.15;

        // Factor 5: Active in last 3 days
        const daysSinceActive = user.lastActive ? 
            (Date.now() - user.lastActive) / (1000 * 60 * 60 * 24) : 30;
        if (daysSinceActive < 3) likelihood += 0.1;

        return Math.min(0.9, likelihood);
    }

    // Engagement Health Score
    // Returns score (0-100) of user engagement health
    calculateEngagementScore(user) {
        let score = 50; // Neutral base

        // Message frequency (30%)
        const messageScore = Math.min(30, (user.messageCount || 0) * 1.5);
        score += messageScore;

        // Recency (30%)
        const daysSinceActive = user.lastActive ? 
            (Date.now() - user.lastActive) / (1000 * 60 * 60 * 24) : 30;
        const recencyScore = Math.max(0, 30 - daysSinceActive * 1);
        score += recencyScore;

        // Emotional positivity (20%)
        const sentimentScore = (user.recentSentiment === 'positive') ? 20 :
                               (user.recentSentiment === 'neutral') ? 10 : 0;
        score += sentimentScore;

        // Follow-through (20%)
        const followScore = (user.followThrough === 'high') ? 20 :
                            (user.followThrough === 'medium') ? 10 : 0;
        score += followScore;

        return Math.min(100, Math.max(0, score));
    }

    // Generate next best action for a user
    getNextBestAction(user) {
        const churnRisk = this.predictChurnRisk(user);
        const upgradeLikelihood = this.predictUpgradeLikelihood(user);
        const engagementScore = this.calculateEngagementScore(user);

        if (churnRisk > 0.6) {
            return {
                action: 're-engagement',
                priority: 'high',
                message: 'Send personalized re-engagement email with a special offer',
                channel: 'email',
                timing: 'immediate'
            };
        }

        if (upgradeLikelihood > 0.6 && user.segment === 'free') {
            return {
                action: 'upgrade_prompt',
                priority: 'high',
                message: 'Show premium upgrade offer with 7-day trial',
                channel: 'in-app',
                timing: 'next_session'
            };
        }

        if (engagementScore < 30) {
            return {
                action: 'nurture',
                priority: 'medium',
                message: 'Send helpful content based on their PLT profile',
                channel: 'email',
                timing: '24h'
            };
        }

        if (user.topics?.profit > 10) {
            return {
                action: 'share_case_study',
                priority: 'medium',
                message: 'Send growth case study from similar business',
                channel: 'in-app',
                timing: 'next_session'
            };
        }

        return {
            action: 'monitor',
            priority: 'low',
            message: 'Continue monitoring engagement',
            channel: 'none',
            timing: 'ongoing'
        };
    }

    // Generate all insights for a user
    generateUserInsights(user) {
        const churnRisk = this.predictChurnRisk(user);
        const upgradeLikelihood = this.predictUpgradeLikelihood(user);
        const engagementScore = this.calculateEngagementScore(user);
        const nextAction = this.getNextBestAction(user);

        // Determine user segment based on insights
        let insightSegment = 'healthy';
        if (churnRisk > 0.7) insightSegment = 'at_risk';
        else if (churnRisk > 0.5) insightSegment = 'warming';
        else if (upgradeLikelihood > 0.6) insightSegment = 'ready_to_upgrade';
        else if (engagementScore < 40) insightSegment = 'dormant';

        return {
            userId: user.id,
            churnRisk: parseFloat(churnRisk.toFixed(2)),
            upgradeLikelihood: parseFloat(upgradeLikelihood.toFixed(2)),
            engagementScore: Math.round(engagementScore),
            segment: insightSegment,
            nextAction: nextAction,
            recommendation: this.getRecommendationText(insightSegment, user),
            predictedLTV: this.predictLTV(user, upgradeLikelihood)
        };
    }

    getRecommendationText(segment, user) {
        switch(segment) {
            case 'at_risk':
                return `⚠️ ${user.email} is at high risk of churn. Send personalized re-engagement offer within 24h.`;
            case 'warming':
                return `🔥 ${user.email} is showing decline. Nurture with value content before they disengage.`;
            case 'ready_to_upgrade':
                return `💰 ${user.email} is ready to upgrade. Show premium offer on next session.`;
            case 'dormant':
                return `💤 ${user.email} is dormant. Re-engagement campaign needed.`;
            default:
                return `✅ ${user.email} is healthy. Monitor engagement and look for upgrade signals.`;
        }
    }

    predictLTV(user, upgradeLikelihood) {
        const currentLTV = user.lifetimeValue || 0;
        if (upgradeLikelihood > 0.6 && user.segment === 'free') {
            return currentLTV + 47; // Premium subscription
        }
        if (user.segment === 'premium') {
            return currentLTV + (47 * 3); // 3 months average retention
        }
        return currentLTV;
    }

    // Batch insights for all users
    generateAllInsights(users) {
        return users.map(user => this.generateUserInsights(user));
    }

    // Get summary statistics
    getSummaryStats(users) {
        const insights = this.generateAllInsights(users);

        return {
            totalUsers: users.length,
            atRisk: insights.filter(i => i.segment === 'at_risk').length,
            readyToUpgrade: insights.filter(i => i.segment === 'ready_to_upgrade').length,
            dormant: insights.filter(i => i.segment === 'dormant').length,
            healthy: insights.filter(i => i.segment === 'healthy').length,
            averageChurnRisk: insights.reduce((sum, i) => sum + i.churnRisk, 0) / users.length,
            averageEngagement: insights.reduce((sum, i) => sum + i.engagementScore, 0) / users.length,
            predictedNextMonthRevenue: insights.reduce((sum, i) => sum + (i.predictedLTV - (i.user.lifetimeValue || 0)), 0)
        };
    }

    // Model initialization (stub for future ML integration)
    initChurnModel() {
        return {
            version: '1.0',
            features: ['recency', 'message_count', 'sentiment', 'follow_through'],
            description: 'Logistic regression model for churn prediction'
        };
    }

    initUpgradeModel() {
        return {
            version: '1.0',
            features: ['message_count', 'emotional_intensity', 'profit_topic_count', 'satisfaction'],
            description: 'Random forest model for upgrade prediction'
        };
    }

    initEngagementModel() {
        return {
            version: '1.0',
            features: ['frequency', 'recency', 'sentiment', 'follow_through'],
            description: 'Heuristic scoring model for engagement health'
        };
    }
}

export default PredictiveInsights;
