        .segment-badge {
            display: inline-block;
            padding: 4px 12px;
            border-radius: 20px;
            font-size: 11px;
        }

        .segment-at_risk { background: #ff666622; border: 1px solid #ff6666; color: #ff6666; }
        .segment-ready_to_upgrade { background: #88ff8822; border: 1px solid #88ff88; color: #88ff88; }
        .segment-warming { background: #ffaa6622; border: 1px solid #ffaa66; color: #ffaa66; }
        .segment-dormant { background: #88888822; border: 1px solid #888888; color: #888888; }
        .segment-healthy { background: #88aaff22; border: 1px solid #88aaff; color: #88aaff; }

        .modal {
            display: none;
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.9);
            backdrop-filter: blur(8px);
            z-index: 1000;
            justify-content: center;
            align-items: center;
        }

        .modal-content {
            background: #0a0a1a;
            border: 1px solid #ffaa44;
            border-radius: 24px;
            max-width: 500px;
            width: 90%;
            padding: 24px;
        }

        .close-modal {
            float: right;
            background: none;
            border: none;
            color: #ffaa44;
            font-size: 24px;
            cursor: pointer;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>📈 PREDICTIVE INSIGHTS</h1>
            <p>AI-powered churn prediction, upgrade likelihood, and engagement intelligence</p>
        </div>

        <div class="stats-grid" id="statsGrid"></div>

        <div class="table-container">
            <table id="insightsTable">
                <thead>
                    <tr>
                        <th>User</th>
                        <th>Segment</th>
                        <th>Churn Risk</th>
                        <th>Upgrade Likelihood</th>
                        <th>Engagement Score</th>
                        <th>Next Best Action</th>
                    </tr>
                </thead>
                <tbody id="insightsTableBody"></tbody>
            </table>
        </div>
    </div>

    <div id="userModal" class="modal">
        <div class="modal-content">
            <button class="close-modal" onclick="closeModal()">&times;</button>
            <h2 id="modalTitle">User Insights</h2>
            <div id="modalContent"></div>
        </div>
    </div>

    <script type="module">
        import PredictiveInsights from '../js/predictive-insights.js';

        // Load user data from localStorage
        function loadUsers() {
            const users = [];
            const usersRaw = localStorage.getItem('pantheon_users');
            if (usersRaw) {
                const usersObj = JSON.parse(usersRaw);
                for (const [email, data] of Object.entries(usersObj)) {
                    // Load personality profile
                    const profileKey = `personality_${email}`;
                    const profileRaw = localStorage.getItem(profileKey);
                    const profile = profileRaw ? JSON.parse(profileRaw) : {};

                    // Load messages for this user
                    const messagesRaw = localStorage.getItem('seshat_messages');
                    const messages = messagesRaw ? JSON.parse(messagesRaw).filter(m => m.userId === email) : [];

                    users.push({
                        id: email,
                        email: email,
                        messageCount: messages.length,
                        lastActive: profile.lastActive || data.createdAt,
                        segment: data.tier || 'free',
                        lifetimeValue: data.totalSpent || 0,
                        topics: profile.topics || {},
                        emotionalIntensity: profile.emotionalIntensity || 0.5,
                        recentSentiment: profile.recentSentiment || 'neutral',
                        followThrough: profile.followThrough || 'medium',
                        messageTrend: profile.messageTrend || 'stable'
                    });
                }
            }
            return users;
        }

        function renderStats(insights, users) {
            const stats = {
                totalUsers: users.length,
                atRisk: insights.filter(i => i.segment === 'at_risk').length,
                readyToUpgrade: insights.filter(i => i.segment === 'ready_to_upgrade').length,
                avgChurnRisk: (insights.reduce((sum, i) => sum + i.churnRisk, 0) / users.length * 100).toFixed(1),
                avgEngagement: Math.round(insights.reduce((sum, i) => sum + i.engagementScore, 0) / users.length),
                predictedRevenue: insights.reduce((sum, i) => sum + (i.predictedLTV - (i.user.lifetimeValue || 0)), 0).toFixed(2)
            };

            const statsGrid = document.getElementById('statsGrid');
            statsGrid.innerHTML = `
                <div class="stat-card"><div class="stat-number">${stats.totalUsers}</div><div>Total Users</div></div>
                <div class="stat-card"><div class="stat-number risk-high">${stats.atRisk}</div><div>At Risk (Churn)</div></div>
                <div class="stat-card"><div class="stat-number risk-low">${stats.readyToUpgrade}</div><div>Ready to Upgrade</div></div>
                <div class="stat-card"><div class="stat-number">${stats.avgChurnRisk}%</div><div>Avg Churn Risk</div></div>
                <div class="stat-card"><div class="stat-number">${stats.avgEngagement}</div><div>Avg Engagement</div></div>
                <div class="stat-card"><div class="stat-number">$${stats.predictedRevenue}</div><div>Predicted Next Month Revenue</div></div>
            `;
        }

        function renderInsightsTable(insights) {
            const tbody = document.getElementById('insightsTableBody');
            tbody.innerHTML = insights.map(insight => `
                <tr onclick="showUserModal('${insight.userId}')">
                    <td style="color: #ffaa66;">${insight.userId}</td>
                    <td><span class="segment-badge segment-${insight.segment}">${insight.segment.replace(/_/g, ' ')}</span></td>
                    <td class="${insight.churnRisk > 0.6 ? 'risk-high' : insight.churnRisk > 0.3 ? 'risk-medium' : 'risk-low'}">${(insight.churnRisk * 100).toFixed(0)}%</td>
                    <td class="${insight.upgradeLikelihood > 0.6 ? 'risk-low' : ''}">${(insight.upgradeLikelihood * 100).toFixed(0)}%</td>
                    <td>${insight.engagementScore}</td>
                    <td style="font-size: 11px;">${insight.nextAction.action}</td>
                </tr>
            `).join('');
        }

        window.showUserModal = function(userId) {
            const insights = JSON.parse(localStorage.getItem('last_insights') || '[]');
            const insight = insights.find(i => i.userId === userId);
            if (!insight) return;

            const modal = document.getElementById('userModal');
            document.getElementById('modalTitle').innerHTML = `🧠 ${userId}`;
            document.getElementById('modalContent').innerHTML = `
                <div style="margin-top: 20px;">
                    <p><strong>Churn Risk:</strong> ${(insight.churnRisk * 100).toFixed(0)}%</p>
                    <p><strong>Upgrade Likelihood:</strong> ${(insight.upgradeLikelihood * 100).toFixed(0)}%</p>
                    <p><strong>Engagement Score:</strong> ${insight.engagementScore}/100</p>
                    <p><strong>Segment:</strong> ${insight.segment}</p>
                    <hr style="margin: 15px 0; border-color: #333;">
                    <p><strong>🎯 Recommended Action:</strong></p>
                    <p style="background: #1a1a2a; padding: 12px; border-radius: 12px; margin-top: 8px;">${insight.recommendation}</p>
                    <p style="margin-top: 12px;"><strong>📈 Predicted LTV:</strong> $${insight.predictedLTV.toFixed(2)}</p>
                </div>
            `;
            modal.style.display = 'flex';
        };

        window.closeModal = function() {
            document.getElementById('userModal').style.display = 'none';
        };

        // Initialize and run
        const predictiveInsights = new PredictiveInsights();
        const users = loadUsers();
        const insights = predictiveInsights.generateAllInsights(users);

        localStorage.setItem('last_insights', JSON.stringify(insights));

        renderStats(insights, users);
        renderInsightsTable(insights);

        // Auto-refresh every 30 seconds
        setInterval(() => {
            const freshUsers = loadUsers();
            const freshInsights = predictiveInsights.generateAllInsights(freshUsers);
            localStorage.setItem('last_insights', JSON.stringify(freshInsights));
            renderStats(freshInsights, freshUsers);
            renderInsightsTable(freshInsights);
        }, 30000);
    </script>
</body>
</html>
